#include<bits/stdc++.h>
using namespace std;
bool a[1005];
int n,m;
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int x;
        cin>>x;
        if(x==1){
            a[n]=!a[n];
        }else{
            a[x-1]=!a[x-1];
        }
        if(x==n){
            a[1]=!a[1];
        }else{
            a[x+1]=!a[x+1];
        }
        a[x]=!a[x];
    }
    for(int i=1;i<=n;i++) cout<<a[i]<<" ";
    return 0;
}
